#include <stdio.h>
#include <stdlib.h>

/* Leftist Tree Node Structure */
typedef struct LeftistNode {
 int key; // The priority value
 int shortest; // s-value: shortest path to external node
 struct LeftistNode *left;
 struct LeftistNode *right;
} LeftistNode;

/* Create a new node with given key */
LeftistNode* createNode(int key) {
 LeftistNode *node = (LeftistNode *)malloc(sizeof(LeftistNode));
 if (node == NULL) {
 printf("Memory allocation failed!\n");
 exit(1);
 }
 node->key = key;
 node->shortest = 1; // Leaf node has s-value = 1
 node->left = NULL;
 node->right = NULL;
 return node;
}

/* Get s-value of a node */
int getShortest(LeftistNode *node) {
 return (node != NULL) ? node->shortest : 0;
}

/* 
 * Merge two min-leftist trees
 * Time Complexity: O(log n)
 * Space Complexity: O(log n) for recursion stack
 */
LeftistNode* merge(LeftistNode *h1, LeftistNode *h2) {
 // Base case: if either tree is empty, return the other
 if (h1 == NULL) return h2;
 if (h2 == NULL) return h1;

 // Ensure h1 has smaller root (min-heap property)
 if (h1->key > h2->key) {
 LeftistNode *temp = h1;
 h1 = h2;
 h2 = temp;
 }

 // Recursively merge right subtree of h1 with h2
 h1->right = merge(h1->right, h2);

 // Restore leftist property: s(left) >= s(right)
 if (getShortest(h1->left) < getShortest(h1->right)) {
 // Swap left and right children
 LeftistNode *temp = h1->left;
 h1->left = h1->right;
 h1->right = temp;
 }

 // Update s-value of root
 h1->shortest = getShortest(h1->right) + 1;

 return h1;
}

/* 
 * Insert a key into the leftist tree
 * Time Complexity: O(log n)
 */
LeftistNode* insert(LeftistNode *root, int key) {
 LeftistNode *newNode = createNode(key);
 return merge(root, newNode);
}

/* 
 * Delete the minimum element (root) from the leftist tree
 * Time Complexity: O(log n)
 * Returns: 1 on success, 0 if tree is empty
 */
LeftistNode* deleteMin(LeftistNode *root, int *minKey) {
 if (root == NULL) {
 printf("Tree is empty.\n");
 *minKey = -1;
 return NULL;
 }

 *minKey = root->key;

 LeftistNode *leftChild = root->left;
 LeftistNode *rightChild = root->right;

 free(root); // Free the old root

 // Merge left and right subtrees
 return merge(leftChild, rightChild);
}

/* Find minimum element (root) - O(1) */
int findMin(LeftistNode *root) {
 return (root != NULL) ? root->key : -1;
}

/* Inorder traversal for verification */
void inorder(LeftistNode *root) {
 if (root == NULL) return;
 inorder(root->left);
 printf("%d(s=%d) ", root->key, root->shortest);
 inorder(root->right);
}

/* Level order traversal to visualize tree */
void levelOrder(LeftistNode *root) {
 if (root == NULL) {
 printf("Tree is empty.\n");
 return;
 }

 // Simple level order using queue
 LeftistNode **queue = (LeftistNode **)malloc(sizeof(LeftistNode *) * 100);
 int front = 0, rear = 0;

 queue[rear++] = root;
 int level = 0;

 printf("Level %d: ", level);

 while (front < rear) {
 int levelSize = rear - front;

 for (int i = 0; i < levelSize; i++) {
 LeftistNode *node = queue[front++];
 printf("%d(s=%d) ", node->key, node->shortest);

 if (node->left) queue[rear++] = node->left;
 if (node->right) queue[rear++] = node->right;
 }

 if (front < rear) {
 printf("\nLevel %d: ", ++level);
 }
 }

 printf("\n");
 free(queue);
}

/* Free all nodes in the tree */
void destroyTree(LeftistNode *root) {
 if (root == NULL) return;
 destroyTree(root->left);
 destroyTree(root->right);
 free(root);
}

/* Test the implementation */
int main() {
 printf("============================================================\n");
 printf("LEFTIST TREE DEMONSTRATION\n");
 printf("============================================================\n");

 // Build first tree manually:
 // 3(s=2)
 // / \
 // 10(s=1) 8(s=2)
 // \
 // 15(s=1)

 LeftistNode *tree1 = createNode(3);
 tree1->shortest = 2;
 tree1->left = createNode(10);
 tree1->left->shortest = 1;
 tree1->right = createNode(8);
 tree1->right->shortest = 2;
 tree1->right->right = createNode(15);
 tree1->right->right->shortest = 1;

 // Build second tree:
 // 6(s=2)
 // / \
 // 12(s=1) 7(s=1)

 LeftistNode *tree2 = createNode(6);
 tree2->shortest = 2;
 tree2->left = createNode(12);
 tree2->left->shortest = 1;
 tree2->right = createNode(7);
 tree2->right->shortest = 1;

 printf("\nTree 1 before merge:\n");
 levelOrder(tree1);
 printf("Inorder: ");
 inorder(tree1);
 printf("\n");

 printf("\nTree 2 before merge:\n");
 levelOrder(tree2);
 printf("Inorder: ");
 inorder(tree2);
 printf("\n");

 // Merge the two trees
 LeftistNode *merged = merge(tree1, tree2);

 printf("\n============================================================\n");
 printf("AFTER MERGE:\n");
 printf("============================================================\n");
 levelOrder(merged);
 printf("Inorder: ");
 inorder(merged);
 printf("\nMinimum: %d\n", findMin(merged));

 // Test insert
 printf("\n============================================================\n");
 printf("INSERTING 5...\n");
 printf("============================================================\n");
 merged = insert(merged, 5);
 levelOrder(merged);
 printf("Minimum: %d\n", findMin(merged));

 // Test delete-min
 int minVal;
 printf("\n============================================================\n");
 printf("DELETING MINIMUM...\n");
 printf("============================================================\n");
 merged = deleteMin(merged, &minVal);
 printf("Deleted minimum: %d\n", minVal);
 levelOrder(merged);
 printf("Minimum: %d\n", findMin(merged));

 // Build tree from scratch using insert
 printf("\n============================================================\n");
 printf("BUILDING TREE FROM SCRATCH\n");
 printf("============================================================\n");
 LeftistNode *root = NULL;
 int keys[] = {20, 10, 30, 5, 15, 25, 35};
 int n = sizeof(keys) / sizeof(keys[0]);

 for (int i = 0; i < n; i++) {
 root = insert(root, keys[i]);
 printf("Inserted %d, minimum = %d\n", keys[i], findMin(root));
 }

 printf("\nFinal tree structure:\n");
 levelOrder(root);

 // Delete all elements
 printf("\nDeleting all elements in order:\n");
 while (root != NULL) {
 root = deleteMin(root, &minVal);
 printf(" Deleted: %d\n", minVal);
 }

 return 0;
}
